#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int words=(N+63)/64;
        uint64_t **bits=(uint64_t**)malloc(N*sizeof(uint64_t*));
        for(int i=0;i<N;i++) bits[i]=(uint64_t*)calloc(words,sizeof(uint64_t));
        char line[2005];
        for(int i=0;i<N;i++){
            scanf("%s",line);
            for(int j=0;j<N;j++) if(line[j]=='1') bits[i][j>>6]|=1ULL<<(j&63);
        }
        long long ans=0;
        for(int i=0;i<N;i++){
            for(int j=i+1;j<N;j++){
                if((bits[i][j>>6]>> (j&63))&1ULL) continue; // already friends
                int common=0;
                for(int w=0;w<words;w++) if(bits[i][w]&bits[j][w]){common=1;break;}
                if(common) ans++;
            }
        }
        printf("%lld\n",ans);
        for(int i=0;i<N;i++) free(bits[i]);
        free(bits);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    const int MAXN=2000;
    static bitset<MAXN> adj[MAXN];
    while(T--){
        int N; cin>>N;
        string s;
        for(int i=0;i<N;i++){
            cin>>s;
            adj[i].reset();
            for(int j=0;j<N;j++) if(s[j]=='1') adj[i].set(j);
        }
        long long ans=0;
        for(int i=0;i<N;i++){
            for(int j=i+1;j<N;j++){
                if(adj[i][j]) continue;
                if((adj[i]&adj[j]).any()) ans++;
            }
        }
        cout<<ans<<"\n";
    }
    return 0;
}

