code.Python3:
import sys

def solve():
    data=sys.stdin.read().split()
    if not data: return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        N=int(next(it))
        rows=[next(it) for _ in range(N)]
        words=(N+63)//64
        bits=[[0]*words for _ in range(N)]
        for i,line in enumerate(rows):
            for j,ch in enumerate(line):
                if ch=='1':
                    bits[i][j>>6]|=1<<(j&63)
        ans=0
        for i in range(N):
            for j in range(i+1,N):
                if (bits[i][j>>6]>> (j&63)) & 1:
                    continue
                common=False
                for w in range(words):
                    if bits[i][w] & bits[j][w]:
                        common=True
                        break
                if common:
                    ans+=1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    solve()

code.JavaScript:
const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
if(input.length===0) process.exit(0);
const T=Number(input[idx++]);
let outputs=[];
for(let tc=0;tc<T;tc++){
  const N=Number(input[idx++]);
  const rows=[];
  for(let i=0;i<N;i++) rows.push(input[idx++]);
  const words=(N+63)>>6;
  const bits=Array.from({length:N},()=>new Uint32Array(words*2));
  for(let i=0;i<N;i++){
    const line=rows[i];
    for(let j=0;j<N;j++) if(line[j]==='1'){
      const w=j>>6;
      const off=j&63;
      if(off<32) bits[i][w*2]|=1<<off; else bits[i][w*2+1]|=1<<(off-32);
    }
  }
  const getBit=(arr,pos)=>{const w=pos>>6; const off=pos&63; return off<32? (arr[w*2]>>>off)&1 : (arr[w*2+1]>>> (off-32))&1;};
  let ans=0;
  for(let i=0;i<N;i++){
    for(let j=i+1;j<N;j++){
      if(getBit(bits[i],j)) continue;
      let common=false;
      for(let w=0;w<words;w++){
        if((bits[i][w*2]&bits[j][w*2])!==0 || (bits[i][w*2+1]&bits[j][w*2+1])!==0){common=true;break;}
      }
      if(common) ans++;
    }
  }
  outputs.push(String(ans));
}
console.log(outputs.join('\n'));

